    /// Accessible label for the thumb. Default: `"Value"`.
    pub thumb_label: MessageFn<dyn Fn(&Locale) -> String + Send + Sync>,
}

impl Default for Messages {
    fn default() -> Self {
        Self {
            thumb_label: MessageFn::static_str("Value"),
        }
    }
}

impl ComponentMessages for Messages {}
